create table if not exists profiles (id uuid primary key, email text unique, role text default 'USER', created_at timestamp with time zone default now());
create table if not exists products (id bigint generated by default as identity primary key, name text not null, price integer not null, category text, description text, image text, stock integer default 0, created_at timestamp with time zone default now());
create table if not exists reviews (id bigint generated by default as identity primary key, product_id bigint, name text, rating integer, text text, created_at timestamp with time zone default now());
create table if not exists orders (id bigint generated by default as identity primary key, customer_name text, email text, phone text, total integer, status text default 'new', created_at timestamp with time zone default now());
